import{_ as d,c as r,o,ag as e}from"./chunks/framework.Ds6Eueu6.js";const a="/assets/01-strategy-vs-benchmark-nav.fw2Lx_5V.png",n="/assets/02-annual-return-comparison.Ckl4Mmrd.png",s="/assets/03-monthly-return-distribution.BWxyl_ic.png",p="/assets/04-underwater-curves.D7uWAXSI.png",i="/assets/05-parameter-sensitivity.CvBMUihc.png",R=JSON.parse('{"title":"第五章：策略好不好？4 个评估角度","description":"","frontmatter":{},"headers":[],"relativePath":"book/q5-how-to-validate.md","filePath":"book/q5-how-to-validate.md","lastUpdated":null}'),h={name:"book/q5-how-to-validate.md"};function l(g,t,c,b,u,k){return o(),r("div",null,t[0]||(t[0]=[e('<h1 id="第五章-策略好不好-4-个评估角度" tabindex="-1">第五章：策略好不好？4 个评估角度 <a class="header-anchor" href="#第五章-策略好不好-4-个评估角度" aria-label="Permalink to &quot;第五章：策略好不好？4 个评估角度&quot;">​</a></h1><p>第四章我们给策略加上了规则——调仓频率、止损、止盈，学会了“不是所有合理的规则都有效”。现在手上有一个“看起来不错”的策略组合：RiskParity + 5% 止损，年化收益、夏普比都还行。</p><p>但“看起来不错”到底是什么意思？年化 15% 好不好？夏普 0.8 够不够？<strong>跟什么比？</strong></p><p>更关键的问题：<strong>这些数字是好几年平均出来的。如果某一年亏了 20%，你扛得住吗？</strong></p><h3 id="路线图" tabindex="-1">路线图 <a class="header-anchor" href="#路线图" aria-label="Permalink to &quot;路线图&quot;">​</a></h3><p>我们正在走一条完整的策略构建之路：</p><p><strong>选什么标的（第二章 已完成）→ 每个买多少（第三章 已完成）→ 什么时候买卖（第四章 已完成）→ 怎么验证有效（第五章 本章）→ 如何避免自欺欺人（第六章）</strong></p><p><strong>这一章你跨进了飞轮的”归因层”——主练动作从前几章的”做”切到”看”。指标是”看”的眼睛，本书的口号”做要规则、看要指标”中”看要指标”指的就是这一层的训练。</strong> 本章给策略做一次”全面体检”，分四步检查四个评估维度，对照如表 5-1 所示。</p><p><strong>表 5-1 第五章四节问题与方法对照</strong></p><table tabindex="0"><thead><tr><th>节</th><th>问题</th><th>方法</th></tr></thead><tbody><tr><td>5.1</td><td>跟什么比？</td><td>基准对比 + 风险调整指标</td></tr><tr><td>5.2</td><td>每年都有收益吗？</td><td>分年拆解</td></tr><tr><td>5.3</td><td>收益结构什么样？</td><td>收益分布 + 水下曲线</td></tr><tr><td>5.4</td><td>参数动一动崩不崩？</td><td>参数敏感性扫描</td></tr></tbody></table><p>铁律不变：<strong>先猜后验，数据说了算。</strong></p><p>本章用第三、四章的四个策略作为“被检查对象”，4 个实验都按统一流程跑——见前言“怎么使用这本书”。四个候选策略对照如表 5-2 所示。</p><p><strong>表 5-2 第五章评估的四个候选策略</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>来源</th><th>特点</th></tr></thead><tbody><tr><td>EqualWeight</td><td>第三章等权</td><td>最简单，无参数</td></tr><tr><td>RiskParity</td><td>第三章风险平价</td><td>稳健，低敏感</td></tr><tr><td>TopNRanking</td><td>第三章动量排名</td><td>高收益但高波动</td></tr><tr><td>RP+止损5%</td><td>第四章最终产出</td><td>RiskParity + 5% 止损</td></tr></tbody></table><blockquote><p>提示：本章 📌 要点比前几章长——因为 q5 spec 涉及金融口径、视觉契约、同方法不同目的等高密度知识，每条都把“为什么、不这样会怎样”写透。读到要点段不必赶——慢一点消化更划算。</p></blockquote><hr><h2 id="_5-1-跟什么比" tabindex="-1">5.1 跟什么比？ <a class="header-anchor" href="#_5-1-跟什么比" aria-label="Permalink to &quot;5.1 跟什么比？&quot;">​</a></h2><p>第四章的策略年化收益 15%、夏普 0.8——好不好？</p><p>直觉告诉我们：收益高就是好，夏普越大越好。但“好”是跟什么比？如果同期市场涨了 20%，你忙活半天不如躺平。</p><p>第一章已经讲过 <strong>Beta</strong>（跟着市场赚的钱）和 <strong>Alpha</strong>（你靠技能多赚的钱）。本章要做的事，就是把 第三、四章 产出的策略放到“跟谁比”的语境里——搞清楚它赚的是 Beta 还是 Alpha。一个策略只赚到 Beta，买指数 ETF 就够了；只有创造出 Alpha，策略才有真正的价值。</p><p>在开始之前，先复习四个你已经见过的“基础体检指标”——它们在第一、二、三章都已经登场过，第一次看到时回来查表 5-3 就好。</p><p><strong>表 5-3 四个基础体检指标速查（第一、二、三章已登场）</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>白话含义</th></tr></thead><tbody><tr><td>累计收益率</td><td>从头到尾总共赚了多少</td></tr><tr><td>年化收益率</td><td>平均每年赚多少</td></tr><tr><td>年化波动率</td><td>价格颠簸程度——数字越大越像坐过山车</td></tr><tr><td>最大回撤</td><td>最惨时从最高点跌了多少——衡量“最坏情况有多坏”</td></tr></tbody></table><p>这四个指标已经够看出策略“赚没赚 / 颠不颠 / 摔得惨不惨”。但它们各自看一面——你还需要一把“综合尺”把收益和风险揉到一起。这把尺第三章已经提过一次（夏普比率）；本章实验跑完后我们<strong>把它和另外两把“换种风险定义”的尺子（卡玛 / 索提诺）一起请上场</strong>。先做实验，再上尺子。</p><h3 id="动手实验-1-策略-vs-买入持有基准" tabindex="-1">动手实验 1：策略 vs 买入持有基准 <a class="header-anchor" href="#动手实验-1-策略-vs-买入持有基准" aria-label="Permalink to &quot;动手实验 1：策略 vs 买入持有基准&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看三件新东西：<strong>金融指标的年化口径必须显式</strong>、<strong>oxq 评估与构造模块都要白话点名</strong>、以及<strong>防 LLM 幻觉的标准句</strong>。</p><blockquote><p>先看完三段演示再回到运行结果——这一节信息会比前面密一些，因为 5.1 是 q5 信息量最大的一节。</p></blockquote><h4 id="起草上下文-任务" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><p>第五章是“看”的一章——把前几章产出的策略放进体检台。上下文不引入新的策略，只把第三、四章的产物集合起来：</p><blockquote><p><strong>上下文</strong>：本章评估策略的有效性。第三、四章产出了 EqualWeight、RiskParity、TopNRanking、RiskParity+5% 止损四个策略，回测指标看起来不错。但“不错”是跟什么比？年化 15% 好不好，取决于同期市场涨了多少。</p><p><strong>任务</strong>：在 notebook <code>q5-how-to-validate.ipynb</code> 中，把四个策略和“等权买入持有”基准放在一起比较，引入多种风险调整指标。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：第五章不引入新策略，只把前几章的产物集中送进体检台。spec 的上下文段把“被检查对象”明确点名——这种“集合体检”型 spec 的好处是：学员的认知负担只在“评估方法”这一条线上，不必再消化新的策略逻辑。</p></blockquote><h4 id="起草要求-模块点名-年化口径" tabindex="-1">起草要求：模块点名 + 年化口径 <a class="header-anchor" href="#起草要求-模块点名-年化口径" aria-label="Permalink to &quot;起草要求：模块点名 + 年化口径&quot;">​</a></h4><p>要求段做两件硬约束。第一件：<strong>白话点名 oxq 评估端和构造端要用哪几个模块</strong>——AI 自己去查接口细节。第二件：<strong>指标的年化方法必须显式锁定</strong>——否则跨次/跨工具的数字对不上账。</p><blockquote><p><strong>要求</strong>：</p><ol><li>评估端使用 oxq 的 <code>RunResult</code>，指标的<strong>计算口径</strong>显式锁定： <ul><li>年化方法：<strong>252 个交易日</strong>（非 365 自然日）</li><li>夏普比：<code>annualized_return / annualized_volatility</code>，无风险利率 <code>rf=0</code></li><li>卡玛比：<code>annualized_return / abs(max_drawdown)</code></li><li>索提诺比：<code>annualized_return / downside_volatility</code>（下行 = 收益 &lt; 0 的标准差）</li><li>基准的夏普比要用同一口径（252 + rf=0）</li></ul></li><li>构造端使用 oxq 的三个组合优化器——等权（<code>EqualWeightOptimizer</code>）、风险平价（<code>RiskParityOptimizer</code>）、动量排名（<code>TopNRankingOptimizer</code>），按各自的构造参数和所需指标实例化</li><li>数据快照固定：<code>START = &quot;2021-01-01&quot;</code>，<code>END = &quot;2025-12-31&quot;</code>（本章数字以此为基准，不要用 <code>today</code>）</li><li>定义辅助函数 <code>run_strategy(portfolio, indicators=None, freq=10, stop_loss=None)</code> 供后续 spec 复用</li><li>运行四个策略 + 构造“等权买入持有”基准（每只 ETF 归一化到 1，等权平均，之后不交易）</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：金融指标的年化口径（252 vs 365、<code>rf=0</code>、下行波动定义）是<strong>专业默契，但 spec 必须写明</strong>。零基础学员不知道这层约定，同一个数字在不同文献里口径不同。如果 spec 不锁，你跑出 1.43，同学跑出 1.27，谁也不知道差在哪——指标 spec 的“精度”恰恰落在这些看不见的小字上。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>评估端 + 构造端两层接口分别点名</strong>——要求 1 锁定评估端（<code>RunResult</code> 的指标计算），要求 2 列出构造端（三个优化器）。零基础学员只需要知道&quot;调谁&quot;,AI 会自己去查接口。spec 把&quot;用哪些模块&quot;白话点清楚就够了，剩下的对照工作交给 AI。</p></blockquote><h4 id="起草结果呈现-动态描述方向" tabindex="-1">起草结果呈现：动态描述方向 <a class="header-anchor" href="#起草结果呈现-动态描述方向" aria-label="Permalink to &quot;起草结果呈现：动态描述方向&quot;">​</a></h4><p>最后一段最关键的不是“画几张图”，而是<strong>怎么让 AI 在不知道结果方向的情况下写出准确的分析文字</strong>：</p><blockquote><p><strong>结果呈现</strong>：</p><ol><li>策略 vs 基准对比表（5 行 × 8 列）：策略名 / 累计收益 / 年化收益 / 波动率 / 最大回撤 / 夏普比 / 卡玛比 / 索提诺比；最后一行是等权买入持有基准</li><li>超额收益（Alpha）表</li><li>净值曲线对比图（figsize 12×6，4 实线 + 1 灰虚线，归一化到 100）</li><li>分析文字（<strong>根据实际数据动态描述方向，不要硬写“更高”或“更低”</strong>）：哪些策略跑赢了基准？三把尺子的冠军是不是同一个？</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>「根据实际数据动态描述方向，不要硬写“更高”或“更低”」是 q5 整章四份 spec 的标准句</strong>。LLM 喜欢“看似中立其实瞎写”——不锁这一句，它会编一段听上去合理但和数据对不上的结论。把这句话当成 q5 的标配，任何要 AI 写“分析文字”的 spec 都该带上。</p></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q5-how-to-validate/specs/spec-01-benchmark-and-metrics.md" target="_blank" rel="noreferrer"><code>specs/spec-01-benchmark-and-metrics.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了一张对比表、一张超额收益表和一张净值曲线图。</p><p>这个实验做了什么？把 第三、四章 产出的四个策略（等权、风险平价、动量排名、风险平价+止损）全部重新跑一遍含成本的回测，同时构造一个“买入持有”基准——等权买入三只 ETF 后不再做任何交易，代表“什么都不做”的结果。然后把五条净值曲线画在一起，用七个指标（累计收益、年化收益、波动率、最大回撤、夏普比、卡玛比、索提诺比）逐一比较，算出每个策略相对基准的超额收益（Alpha）。</p><p><strong>运行结果</strong></p><p>四个策略与基准的指标对比如表 5-4 所示。</p><p><strong>表 5-4 四个策略 vs 等权买入持有基准的指标对比</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>累计收益</th><th>年化收益</th><th>波动率</th><th>最大回撤</th><th>夏普比</th><th>卡玛比</th><th>索提诺比</th></tr></thead><tbody><tr><td>EqualWeight</td><td>84.37%</td><td>12.33%</td><td>12.49%</td><td>-16.86%</td><td>1.05</td><td>0.73</td><td>0.92</td></tr><tr><td>RiskParity</td><td>98.01%</td><td>13.77%</td><td>11.16%</td><td>-12.81%</td><td>1.29</td><td>1.08</td><td>1.16</td></tr><tr><td>TopNRanking</td><td>153.03%</td><td>18.71%</td><td>15.77%</td><td>-17.77%</td><td>1.27</td><td>1.05</td><td>1.11</td></tr><tr><td>RP+止损5%</td><td>106.23%</td><td>14.59%</td><td>10.61%</td><td>-13.07%</td><td>1.43</td><td>1.12</td><td>1.33</td></tr><tr><td>等权买入持有</td><td>94.82%</td><td>14.39%</td><td>13.00%</td><td>-17.24%</td><td>1.10</td><td>—</td><td>—</td></tr></tbody></table><p>超额收益 / Alpha（策略累计 — 基准累计 94.82%）如表 5-5 所示。</p><p><strong>表 5-5 四个策略相对等权买入持有基准的 Alpha</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>Alpha</th></tr></thead><tbody><tr><td>EqualWeight</td><td>-10.45%</td></tr><tr><td>RiskParity</td><td>+3.18%</td></tr><tr><td>TopNRanking</td><td>+58.20%</td></tr><tr><td>RP+止损5%</td><td>+11.41%</td></tr></tbody></table><p>净值曲线对比如图 5-1 所示。</p><p><img src="'+a+'" alt="策略 vs 买入持有基准"></p><h3 id="结果解读" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>第一个认知升级：<strong>“好不好”必须有参照物。</strong></p><p><strong>基准（Benchmark）</strong> —— 用来做比较的参照物。这里的基准是“什么都不做”——等权买入三只 ETF 后不再交易。就像考试的“及格线”，不跟基准比，你根本不知道自己的策略是好还是坏。</p><p>年化 14% 听起来很棒，但等权买入持有同期也赚了 14.39%。EqualWeight 忙活了一堆操作，累计收益 84.37%，反而没跑赢“什么都不做”的 94.82%——你忙活半天不如躺平。</p><p>跑赢基准的部分叫 <strong>超额收益（Alpha）</strong>——回忆一下 Alpha：第一章用电梯/楼梯类比讲过，Beta 是跟着市场赚的钱（被电梯抬着上楼），Alpha 是比市场多赚的钱（靠你自己爬楼梯爬出来的部分），是你的技能回报。这一章把它放回”有了基准之后才能算”的语境再用一次——上面对比表里的”基准累计 94.82%”就是那部电梯，每个策略减去基准的差额才是 Alpha。EqualWeight 的 Alpha 是 -10.45%，说明它不但没创造技能回报，反而因为频繁调仓的交易成本”亏”了。TopNRanking 的 Alpha 最高（+58.20%），但先别急着下结论——看看其他指标怎么说。</p><p>第二个发现：<strong>不同的尺子量出不同的结论。</strong></p><p>实验跑完了，<strong>正式介绍三把“综合尺”</strong>——它们各自把收益和风险揉到一起，但对“风险”的定义不同：</p><ul><li><strong>夏普比率（Sharpe Ratio）</strong> —— 第三章见过：年化收益除以年化波动率。把“收益高”和“颠簸大”折成一个数字。</li><li><strong>卡玛比（Calmar Ratio）</strong> —— 年化收益除以最大回撤。每承受 1% 的最大回撤，能换来多少年化收益。如果你最怕“一次跌太深”，卡玛比是最直接的尺子。</li><li><strong>索提诺比（Sortino Ratio）</strong> —— 只用<strong>下行波动率</strong>做分母。上涨波动不是风险——涨得猛不应该被惩罚，所以比夏普比更“公平”。</li></ul><p>简单记忆：<strong>夏普看“颠不颠”，卡玛看“摔多惨”，索提诺只关心“亏的部分”。</strong></p><p>把这三把尺子放进表 5-4 之后回头看——三把尺子的冠军都是 RP+止损5%：夏普比 1.43、卡玛比 1.12、索提诺比 1.33。TopNRanking 虽然收益最高，但三把尺子都不是冠军。这次三把尺子碰巧给出了同一个冠军，但不是每次都这么巧——不同的尺子关注不同的风险维度，完全可能给出不同的答案。你最怕什么风险，就用什么尺子。</p><p>但这些都是好几年平均出来的数字。<strong>平均年化 14% 听着不错——但如果其中一年亏了 20%，你扛得住吗？</strong></p><hr><h2 id="_5-2-每年都有收益吗" tabindex="-1">5.2 每年都有收益吗？ <a class="header-anchor" href="#_5-2-每年都有收益吗" aria-label="Permalink to &quot;5.2 每年都有收益吗？&quot;">​</a></h2><p>刚才的指标覆盖了 2021 年初到 2026 年 3 月，整整 5 年多、1250 个交易日。这么长时间的平均值，可能掩盖某些年份的亏损。就像考试平均 80 分，但其中一科考了 30 分。</p><p>直觉告诉我们：平均好就是好吧，哪年赚哪年亏不重要？</p><p>真的吗？拆开看看。</p><h3 id="动手实验-2-逐年收益拆解" tabindex="-1">动手实验 2：逐年收益拆解 <a class="header-anchor" href="#动手实验-2-逐年收益拆解" aria-label="Permalink to &quot;动手实验 2：逐年收益拆解&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>接续型 spec 共享 notebook 状态</strong>、以及<strong>时间维度切片要避免重复回测</strong>。</p><h4 id="起草上下文-任务-1" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-1" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><p>spec-02 不需要重新介绍策略——它直接接着 spec-01 在同一个 notebook 里跑。上下文段把“已经有什么”列清楚就够了：</p><blockquote><p><strong>上下文</strong>：在 <code>q5-how-to-validate.ipynb</code> 中已有四个策略 vs 基准的整体指标对比、<code>results</code> 字典、<code>run_strategy</code> 辅助函数、<code>TNR_PORTFOLIO</code> 等变量。学员已了解基准、超额收益（Alpha）、卡玛比/索提诺比等概念。</p><p><strong>任务</strong>：按年度拆解策略表现，并深挖 TopNRanking 在负收益年份的异常。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：q5 章四份 spec 共享同一个 notebook 状态——spec-02 直接读 spec-01 留下的 <code>results</code>/<code>run_strategy</code>/<code>TNR_PORTFOLIO</code>。<strong>接续型 spec 的上下文段不必再声明，只列“已经有什么”</strong>。这样 AI 不会重新下载数据、不会重新构建策略、不会假设一个不存在的变量。</p></blockquote><h4 id="起草要求-时间切片-缓存复用" tabindex="-1">起草要求：时间切片 + 缓存复用 <a class="header-anchor" href="#起草要求-时间切片-缓存复用" aria-label="Permalink to &quot;起草要求：时间切片 + 缓存复用&quot;">​</a></h4><p>要求段做两件事：① 按年度切片计算指标；② 深挖 TopNRanking 在负收益年份——<strong>这里是最容易让数字打脸的地方</strong>：</p><blockquote><p><strong>要求</strong>：</p><ol><li>用 oxq <code>RunResult</code> 的日收益序列（<code>daily_returns()</code>）和净值曲线（<code>equity_curve</code>）做时间切片</li><li>按年度拆解四策略 + 基准：用 <code>daily_returns()</code> 按年分组，计算年收益率（累乘）、年波动率、年夏普比、年内最大回撤。<strong>跳过样本不足的年份</strong>（<code>if len(year_data) &lt; 20: continue</code>，避开新年初只有几个交易日的边界）</li><li>打印逐年对比表（pandas DataFrame，存入变量 <code>annual_df</code> 供后续 spec 复用）</li><li>画逐年收益柱状图（figsize 14×6，每年一组 5 根柱子，与 spec-01 颜色一致）</li><li>深挖 TopNRanking 负收益年份——扫描 <code>mom_periods = [5, 10, 15, 20, 25, 30]</code>，<strong>每个窗口只跑一次回测，结果存入 <code>deep_dive[period]</code></strong>，从字典里直接读，不要重新调用 <code>run_strategy</code> 做“是否所有窗口都亏”的二次判断</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>时间维度切片不要重复回测</strong>。“按年度拆”听起来要每年都跑一遍——错。整段时间只跑一次，得到日收益序列后按 <code>index.year</code> 分组算指标。深挖也一样：6 个动量窗口跑 6 次,<strong>不要因为后面要二次判断又跑 6 次</strong>。spec 不点名“结果存 dict 复用”，AI 写出的代码大概率会跑 12 次。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>最小样本过滤是隐式约定</strong>。年内 &lt; 20 个交易日不进表，是金融统计的默契。spec 不写明，AI 可能用 1 月份的 5 天数据计算“年化”得出离谱数字——表上突然多出一行“2026 年化 +800%”，学员看不出哪里错了。</p></blockquote><h4 id="起草结果呈现" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：</p><ol><li>逐年收益对比表（DataFrame，行=年份，列=4 策略+基准，负收益用 <code>*</code> 标注）</li><li>逐年收益柱状图</li><li>TopNRanking 异常年份深挖表（行=动量窗口，列=负收益年份）</li><li>分析文字（<strong>根据实际数据动态描述方向</strong>）：哪些策略“每年都赚”？深挖结论是“参数没选对”还是“策略结构性问题”？</li></ol></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q5-how-to-validate/specs/spec-02-annual-breakdown.md" target="_blank" rel="noreferrer"><code>specs/spec-02-annual-breakdown.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了逐年对比表、柱状图和一份 TopNRanking 深挖分析。</p><p>这个实验做了什么？把 Step 1 的整体指标拆成逐年成绩单——按年份分组计算每个策略和基准的年收益率、年波动率、年内最大回撤，看看哪些策略“每年都赚”、哪些有负收益年份。然后针对 TopNRanking 在负收益年份做深挖：换遍 6 种动量窗口（5/10/15/20/25/30 天）重新跑回测，看这一年的亏损是参数选错了，还是策略本身的结构性问题。</p><p><strong>运行结果</strong></p><p>四个策略 + 基准的逐年收益拆解如表 5-6 所示（<code>*</code> 标注负收益年份）。</p><p><strong>表 5-6 四策略与基准逐年收益对比</strong></p><table tabindex="0"><thead><tr><th>年份</th><th>EqualWeight</th><th>RiskParity</th><th>TopNRanking</th><th>RP+止损5%</th><th>基准</th></tr></thead><tbody><tr><td>2021</td><td>3.76%</td><td>1.03%</td><td>-10.09% *</td><td>3.04%</td><td>4.09%</td></tr><tr><td>2022</td><td>-12.72% *</td><td>-8.55% *</td><td>3.04%</td><td>-8.63% *</td><td>-13.44% *</td></tr><tr><td>2023</td><td>17.04%</td><td>15.03%</td><td>23.48%</td><td>15.67%</td><td>21.21%</td></tr><tr><td>2024</td><td>27.55%</td><td>30.12%</td><td>24.50%</td><td>30.65%</td><td>28.31%</td></tr><tr><td>2025</td><td>31.29%</td><td>39.01%</td><td>62.02%</td><td>40.74%</td><td>32.10%</td></tr><tr><td>2026</td><td>3.88%</td><td>3.00%</td><td>9.65%</td><td>3.00%</td><td>5.24%</td></tr></tbody></table><p>逐年收益的柱状对比如图 5-2 所示。</p><p><img src="'+n+'" alt="逐年收益对比"></p><p>深挖 TopNRanking 在 2021 年的负收益——把动量窗口换遍，结果如表 5-7 所示。</p><p><strong>表 5-7 TopNRanking 2021 年不同动量窗口的年收益</strong></p><table tabindex="0"><thead><tr><th>窗口</th><th>2021</th></tr></thead><tbody><tr><td>period=5</td><td>-9.48%</td></tr><tr><td>period=10</td><td>-7.97%</td></tr><tr><td>period=15</td><td>-5.08%</td></tr><tr><td>period=20</td><td>-10.09%</td></tr><tr><td>period=25</td><td>-11.09%</td></tr><tr><td>period=30</td><td>-9.14%</td></tr></tbody></table><p>所有动量窗口在 2021 年都亏钱。</p><h3 id="结果解读-1" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-1" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p><strong>分段检验（Segment Analysis）</strong> —— 把回测结果按时间段拆开检查。整体指标是“平均分”，逐年拆开才是“每科成绩单”——整体及格不等于每科都及格。</p><p>拆开后两个重要发现：</p><p><strong>第一，没有哪个策略“年年赚钱”。</strong> EqualWeight、RiskParity 和 RP+止损5% 在 2022 年都出现了负收益，同期基准也亏了 -13.44%——策略和基准一起亏，说明策略并没有真正提供“下跌保护”。这是资产配置策略的特点：它能分散风险，但不能消除市场整体下跌带来的损失。</p><p><strong>第二，TopNRanking 的负收益不是参数问题。</strong> 2021 年，TopNRanking 是唯一亏钱的策略（-10.09%），而其他三个策略和基准都是正收益。换遍所有动量窗口（5 天到 30 天），在 2021 年全部亏钱。这是<strong>动量策略的结构性弱点</strong>。</p><p><strong>动量滞后性</strong> —— 动量指标基于“过去涨了多少”来判断买什么。但当市场反复上下波动、没有明确方向时，过去涨得好的恰恰可能是“已经涨到头了”的那个。动量指标看的是后视镜——它有天然的滞后性。2021 年的市场就是典型的来回波动环境，动量策略在这种环境下注定吃亏，换什么参数都救不了。</p><p><strong>数据说了算：逐年拆开，才能看到整体指标掩盖的问题。不同策略类型有不同的市场环境偏好。</strong></p><p>但年度还是太粗了——知道了哪年亏钱，但赚钱的年份里，是每月稳稳地赚，还是靠某几个月的暴利覆盖其他月份的亏损？</p><hr><h2 id="_5-3-收益结构什么样" tabindex="-1">5.3 收益结构什么样？ <a class="header-anchor" href="#_5-3-收益结构什么样" aria-label="Permalink to &quot;5.3 收益结构什么样？&quot;">​</a></h2><p>年度表现解释了“什么时候赚、什么时候亏”，但没解释“怎么赚的”——是每个月稳稳地赚一点，还是靠几次大赚覆盖很多次小亏？</p><p>同样赚钱的两个策略，赚法可能完全不同。你能接受“一年中 8 个月亏钱、靠 4 个月大赚拉回来”的策略吗？</p><p>另外，回撤不只是一个数字——最大回撤 -15% 但 3 个月恢复，和最大回撤 -10% 但 1 年没恢复，哪个更痛苦？</p><h3 id="动手实验-3-月度分布-回撤深度" tabindex="-1">动手实验 3：月度分布 + 回撤深度 <a class="header-anchor" href="#动手实验-3-月度分布-回撤深度" aria-label="Permalink to &quot;动手实验 3：月度分布 + 回撤深度&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>视觉契约要写到颜色与子图布局</strong>、以及<strong>关键阈值（包括看似微小的 -0.001）必须显式</strong>。</p><h4 id="起草上下文-任务-2" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-2" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><p>接续 spec-02 的发现：胜率全时段都差不多，但 2021 年有人亏 10% 有人赚 3%。这一份 spec 把“为什么差距这么大”拆开看：</p><blockquote><p><strong>上下文</strong>：notebook 里已有四策略 vs 基准的整体对比、逐年拆解、TopNRanking 在反复波动市场中的结构性弱点。</p><p><strong>任务</strong>：分析月度收益分布和历史回撤事件——同样赚钱的策略，赚法可能完全不同。</p></blockquote><h4 id="起草要求-阈值显式-视觉契约" tabindex="-1">起草要求：阈值显式 + 视觉契约 <a class="header-anchor" href="#起草要求-阈值显式-视觉契约" aria-label="Permalink to &quot;起草要求：阈值显式 + 视觉契约&quot;">​</a></h4><p>第一组要求做月度分布。第二组做回撤事件——<strong>回撤事件的“什么算事件”阈值是这份 spec 最容易被遗漏的精度点</strong>：</p><blockquote><p><strong>要求</strong>：</p><ol><li>用 oxq <code>RunResult</code> 的月度收益（<code>monthly_returns()</code>）和回撤序列（<code>drawdown_series()</code>）做收益结构分析</li><li>月度分布分析（四策略）：胜率、平均盈利月、平均亏损月、盈亏比、盈亏因子、最长连赢/连亏（<strong>月收益 = 0 算亏损</strong>）</li><li>打印月度统计对比表 + 画月度收益分布直方图（figsize 14×8，2×2 子图，20 bins，x=0 处红色虚线）</li><li>回撤深度分析——识别每次回撤事件，<strong>阈值锁定 <code>THRESHOLD = -0.001</code></strong>（即跌幅 ≥ 0.1% 才算事件，避开数值噪声生成假事件）：起点 = dd 跌穿阈值的那天，恢复 = dd 反弹回阈值之上的那天，未恢复则标“—”</li><li>打印每个策略前 5 大回撤事件 + 回撤汇总</li><li>画水下曲线（figsize 14×10，4 子图垂直，<strong>与 spec-01 同色继承</strong>：EW=#4472C4 / RP=#ED7D31 / TNR=#70AD47 / RP+止损=#FFC000）</li><li>拆解 TopNRanking 2021 年月度——证明胜率 50% 但盈亏比 0.47 的“胜率陷阱”</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>视觉契约的“阈值”包括看不见的数字</strong>。回撤事件的 <code>THRESHOLD = -0.001</code> 看似微不足道，但它直接决定有多少行进表——<code>-0.001</code> 可能给你 50 个事件，<code>-0.01</code> 可能只剩 10 个。spec 不锁阈值，AI 选不同值得出完全不同的“前 5 大回撤”，学员两次跑结果对不上账，根本不知道差在哪。<strong>任何“看起来微小”的阈值都是 spec 必写项</strong>。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>跨 spec 颜色继承</strong>。spec-01 的净值曲线用了 4 个颜色，spec-03 的水下曲线必须沿用——否则学员从“绿色 = TNR 净值线”到“水下曲线全是蓝色”，无法联结哪条是 TNR。q5 章一开始就锁的“视觉编码”（颜色、figsize、布局）要在每份后续 spec 显式继承，不能假设 AI 会自动记住。</p></blockquote><h4 id="起草结果呈现-1" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-1" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：月度统计表（4 行）+ 月度直方图（2×2）+ TopNRanking 2021 年逐月明细 + 四策略 2021 月度对比 + 前 5 大回撤事件表 + 回撤汇总表 + 水下曲线图（4 子图）+ 分析文字（<strong>根据实际数据动态描述方向</strong>）</p></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q5-how-to-validate/specs/spec-03-return-distribution-and-drawdown.md" target="_blank" rel="noreferrer"><code>specs/spec-03-return-distribution-and-drawdown.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了月度统计表、分布直方图、2021 年胜率陷阱分析、回撤事件表和水下曲线图。</p><p>这个实验做了什么？从两个维度拆解“怎么赚的钱”。第一个维度是月度收益分布——把每个策略的日收益按月汇总，统计胜率（赚钱月占比）、盈亏比（平均赚多少 vs 平均亏多少）、最长连赢/连亏月数等。还专门拆解了 TopNRanking 2021 年的逐月明细，和其他三个策略对比同年的胜率和盈亏比，解释为什么胜率差不多、结局却完全不同。第二个维度是回撤深度——识别每次从高点下跌到恢复的完整事件，记录深度、下跌天数、恢复天数，画出水下曲线。</p><p>内容比较多，我们分两个维度来看。</p><p><strong>维度一：月度收益分布</strong></p><p>四个策略的月度统计指标如表 5-8 所示。</p><p><strong>表 5-8 四策略月度收益统计对比</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>胜率</th><th>平均盈利月</th><th>平均亏损月</th><th>盈亏比</th><th>盈亏因子</th><th>最好月</th><th>最差月</th><th>连赢</th><th>连亏</th></tr></thead><tbody><tr><td>EqualWeight</td><td>63.5%</td><td>2.54%</td><td>-1.63%</td><td>1.55</td><td>2.70</td><td>9.52%</td><td>-7.82%</td><td>8</td><td>3</td></tr><tr><td>RiskParity</td><td>61.9%</td><td>2.79%</td><td>-1.56%</td><td>1.79</td><td>2.91</td><td>11.29%</td><td>-6.09%</td><td>11</td><td>4</td></tr><tr><td>TopNRanking</td><td>61.9%</td><td>3.88%</td><td>-2.21%</td><td>1.75</td><td>2.85</td><td>9.88%</td><td>-8.36%</td><td>11</td><td>4</td></tr><tr><td>RP+止损5%</td><td>63.5%</td><td>2.77%</td><td>-1.55%</td><td>1.79</td><td>3.12</td><td>11.74%</td><td>-5.52%</td><td>11</td><td>4</td></tr></tbody></table><p>四个策略的月度收益分布直方图如图 5-3 所示。</p><p><img src="'+s+'" alt="月度收益分布"></p><p>乍一看，四个策略的胜率都差不多——62% 左右。但 Step 2 告诉我们 TopNRanking 在 2021 年亏了 10%，而其他策略同年都是正收益。胜率差不多，为什么结局完全不同？拆解 2021 年的月度数据就能看清原因。</p><p><strong>拆解 TopNRanking 2021 年——胜率的陷阱</strong></p><p>TopNRanking 在 2021 年的逐月收益如表 5-9 所示。</p><p><strong>表 5-9 TopNRanking 2021 年逐月明细</strong></p><table tabindex="0"><thead><tr><th>月份</th><th>收益</th></tr></thead><tbody><tr><td>2021-01</td><td>0.00%</td></tr><tr><td>2021-02</td><td>-7.29%</td></tr><tr><td>2021-03</td><td>-1.44%</td></tr><tr><td>2021-04</td><td>+1.93%</td></tr><tr><td>2021-05</td><td>+1.54%</td></tr><tr><td>2021-06</td><td>-1.78%</td></tr><tr><td>2021-07</td><td>+1.17%</td></tr><tr><td>2021-08</td><td>+2.28%</td></tr><tr><td>2021-09</td><td>-4.30%</td></tr><tr><td>2021-10</td><td>+1.12%</td></tr><tr><td>2021-11</td><td>+0.75%</td></tr><tr><td>2021-12</td><td>-4.05%</td></tr></tbody></table><p>把四个策略放在 2021 这一年同一张表里对比，胜率与盈亏比的差异如表 5-10 所示。</p><p><strong>表 5-10 四策略 2021 年月度胜率与盈亏比对比</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>胜率</th><th>平均盈利月</th><th>平均亏损月</th><th>盈亏比</th><th>年收益</th></tr></thead><tbody><tr><td>EqualWeight</td><td>50%</td><td>2.03%</td><td>-1.37%</td><td>1.48</td><td>3.76%</td></tr><tr><td>RiskParity</td><td>58%</td><td>1.76%</td><td>-2.20%</td><td>0.80</td><td>1.03%</td></tr><tr><td>TopNRanking</td><td>50%</td><td>1.46%</td><td>-3.14%</td><td>0.47</td><td>-10.09%</td></tr><tr><td>RP+止损5%</td><td>58%</td><td>1.77%</td><td>-1.82%</td><td>0.97</td><td>3.04%</td></tr></tbody></table><p>看上面的 2021 年对比——TopNRanking 的胜率 50%，跟 EqualWeight 一样。但它赚的月份平均只赚 1.46%，亏的月份平均亏 3.14%，盈亏比只有 0.47。翻译一下：赚的时候赚得少，亏的时候亏得狠。结果：虽然一半的月份赚钱，但亏损月把所有利润全吃掉还倒贴了，全年 -10.09%。</p><p>同年的 EqualWeight 胜率也是 50%，但盈亏比 1.48——赚的月份平均赚 2.03%，亏的月份平均只亏 1.37%。同样的胜率，完全不同的结局。</p><p>这就是 <strong>胜率的陷阱</strong> —— 大多数人天然觉得“赢的次数越多越好”，但胜率本身意义不大。胜率 90%，每次赚 1 元；亏的那 10% 每次亏 20 元。10 次交易赚 9 元、亏 20 元，净亏 11 元。高胜率，亏钱。</p><p>真正决定收益的是 <strong>盈亏比（Win/Loss Ratio）</strong> —— 平均每次赚多少除以平均每次亏多少。优秀策略的秘诀是“小亏大赚”：用止损果断控制亏损幅度（小亏），赶上趋势时让利润奔跑（大赚）。追求高胜率，往往是捡了芝麻丢了西瓜。</p><p><strong>盈亏因子（Profit Factor）</strong> —— 总盈利除以总亏损的绝对值。大于 1 说明赚的比亏的多，大于 2 算优秀。四个策略的盈亏因子都在 2.7-3.1 之间，都算优秀。但注意这是全时段的数字——拆到具体年份（比如 2021），TopNRanking 的盈亏因子会远低于 1。</p><p><strong>维度二：回撤深度</strong></p><p><strong>前 5 大回撤事件</strong></p><p>EqualWeight 的前 5 大回撤事件如表 5-11 所示。</p><p><strong>表 5-11 EqualWeight 前 5 大回撤事件</strong></p><table tabindex="0"><thead><tr><th>#</th><th>开始</th><th>最低点</th><th>恢复</th><th>深度</th><th>下跌天数</th><th>恢复天数</th></tr></thead><tbody><tr><td>1</td><td>2021-11-22</td><td>2022-10-28</td><td>2023-06-16</td><td>-16.86%</td><td>340</td><td>231</td></tr><tr><td>2</td><td>2021-02-18</td><td>2021-03-09</td><td>2021-11-15</td><td>-9.88%</td><td>19</td><td>251</td></tr><tr><td>3</td><td>2025-02-20</td><td>2025-04-07</td><td>2025-05-06</td><td>-9.22%</td><td>46</td><td>29</td></tr><tr><td>4</td><td>2026-01-30</td><td>2026-02-02</td><td>未恢复</td><td>-7.95%</td><td>3</td><td>—</td></tr><tr><td>5</td><td>2024-07-18</td><td>2024-08-05</td><td>2024-09-26</td><td>-7.82%</td><td>18</td><td>52</td></tr></tbody></table><p>最大回撤: -16.86% / 平均恢复: 17天 / 最长恢复: 251天</p><p>RiskParity 的前 5 大回撤事件如表 5-12 所示。</p><p><strong>表 5-12 RiskParity 前 5 大回撤事件</strong></p><table tabindex="0"><thead><tr><th>#</th><th>开始</th><th>最低点</th><th>恢复</th><th>深度</th><th>下跌天数</th><th>恢复天数</th></tr></thead><tbody><tr><td>1</td><td>2021-11-22</td><td>2022-10-28</td><td>2023-05-19</td><td>-12.81%</td><td>340</td><td>203</td></tr><tr><td>2</td><td>2021-02-22</td><td>2021-03-09</td><td>2021-07-15</td><td>-7.98%</td><td>15</td><td>128</td></tr><tr><td>3</td><td>2025-02-20</td><td>2025-04-07</td><td>2025-04-16</td><td>-6.72%</td><td>46</td><td>9</td></tr><tr><td>4</td><td>2026-01-30</td><td>2026-02-02</td><td>未恢复</td><td>-6.02%</td><td>3</td><td>—</td></tr><tr><td>5</td><td>2024-07-19</td><td>2024-08-05</td><td>2024-09-26</td><td>-5.94%</td><td>17</td><td>52</td></tr></tbody></table><p>最大回撤: -12.81% / 平均恢复: 15天 / 最长恢复: 203天</p><p>TopNRanking 的前 5 大回撤事件如表 5-13 所示。</p><p><strong>表 5-13 TopNRanking 前 5 大回撤事件</strong></p><table tabindex="0"><thead><tr><th>#</th><th>开始</th><th>最低点</th><th>恢复</th><th>深度</th><th>下跌天数</th><th>恢复天数</th></tr></thead><tbody><tr><td>1</td><td>2021-02-22</td><td>2022-06-01</td><td>2023-03-20</td><td>-17.77%</td><td>464</td><td>292</td></tr><tr><td>2</td><td>2026-01-30</td><td>2026-02-02</td><td>未恢复</td><td>-14.39%</td><td>3</td><td>—</td></tr><tr><td>3</td><td>2024-07-10</td><td>2024-09-04</td><td>2024-12-17</td><td>-14.02%</td><td>56</td><td>104</td></tr><tr><td>4</td><td>2023-07-20</td><td>2023-12-05</td><td>2024-02-23</td><td>-9.34%</td><td>138</td><td>80</td></tr><tr><td>5</td><td>2025-04-23</td><td>2025-04-28</td><td>2025-06-30</td><td>-6.48%</td><td>5</td><td>63</td></tr></tbody></table><p>最大回撤: -17.77% / 平均恢复: 14天 / 最长恢复: 292天</p><p>RP+止损5% 的前 5 大回撤事件如表 5-14 所示。</p><p><strong>表 5-14 RP+止损5% 前 5 大回撤事件</strong></p><table tabindex="0"><thead><tr><th>#</th><th>开始</th><th>最低点</th><th>恢复</th><th>深度</th><th>下跌天数</th><th>恢复天数</th></tr></thead><tbody><tr><td>1</td><td>2021-11-22</td><td>2022-10-21</td><td>2023-05-19</td><td>-13.07%</td><td>333</td><td>210</td></tr><tr><td>2</td><td>2021-02-22</td><td>2021-03-09</td><td>2021-05-18</td><td>-6.06%</td><td>15</td><td>70</td></tr><tr><td>3</td><td>2026-01-30</td><td>2026-02-02</td><td>未恢复</td><td>-6.02%</td><td>3</td><td>—</td></tr><tr><td>4</td><td>2024-07-19</td><td>2024-08-05</td><td>2024-09-26</td><td>-5.94%</td><td>17</td><td>52</td></tr><tr><td>5</td><td>2025-02-20</td><td>2025-04-07</td><td>2025-04-11</td><td>-5.57%</td><td>46</td><td>4</td></tr></tbody></table><p>最大回撤: -13.07% / 平均恢复: 13天 / 最长恢复: 210天</p><p>四个策略的水下曲线如图 5-4 所示，可以直观看到“在水下度过的时间”。</p><p><img src="'+p+'" alt="水下曲线"></p><h3 id="结果解读-2" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-2" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>收益结构揭示了“怎么赚的钱”——两个关键维度。</p><p><strong>胜率是陷阱，盈亏比才是关键。</strong> 四个策略全时段的胜率都在 62% 左右，看不出差别。但拆到 2021 年，TopNRanking 的盈亏比只有 0.47——每赚 1 块钱，对应要亏 2 块多。同年 EqualWeight 盈亏比 1.48，赚的月份能覆盖亏的月份。同样的胜率，截然不同的结局。真正决定收益的不是赢的次数，而是赢的时候赚多少。</p><p><strong>回撤不只是深度，还有恢复时间。</strong> TopNRanking 的最大回撤 -17.77%，从 2021 年 2 月开始下跌，直到 2023 年 3 月才恢复——整整两年在“水下”。RiskParity 最大回撤 -12.81%，恢复用了 203 天。RP+止损5% 最大回撤 -13.07%，恢复用了 210 天。</p><p><strong>水下曲线（Underwater Curve）</strong> —— 每天距离历史最高点跌了多少。它直观展示一个残酷的事实：你有多少时间是在“还没回本”的状态中度过的。回撤不只是一个数字——它是一段煎熬。深度和恢复时间同样重要。</p><p><strong>回撤恢复时间</strong> —— 从最低点爬回前高需要多久。回撤 -15% 但 3 个月恢复，vs 回撤 -10% 但 1 年没恢复——后者对实际持有体验的伤害更大。比起回撤深度，恢复时间更影响你能不能拿得住。</p><p><strong>数据说了算：赚钱的方式和赚钱一样重要。</strong> 别被高胜率迷惑，关注盈亏比；别只看回撤深度，还要看恢复时间。</p><p>评估够全面了吗？其实还有一个隐藏问题——你用的参数（动量窗口 20 天、波动率窗口 20 天、止损阈值 5%）是回测出来的“最优值”。但如果把 20 天前后扰动一下，比如改成 15 天或 25 天，结果还差不多吗？如果稍微一动就天差地别，那这个“最优”在未来的数据上恐怕也靠不住。</p><hr><h2 id="_5-4-参数动一动-崩不崩" tabindex="-1">5.4 参数动一动，崩不崩？ <a class="header-anchor" href="#_5-4-参数动一动-崩不崩" aria-label="Permalink to &quot;5.4 参数动一动，崩不崩？&quot;">​</a></h2><p>前面三步的评估都基于特定参数——动量窗口 20 天、波动率窗口 20 天、止损阈值 5%。这些参数是回测跑出来的，在历史数据上表现最好。</p><p>但问题是：在最优参数附近前后扰动一下——比如动量窗口从 20 天改成 15 天或 25 天——结果是差不多，还是会差很多？如果附近的参数表现都还行，说明这个”最优”是真的稳；如果稍微一动夏普就从 1.27 跌到 0.85，那历史上的”最优”很可能在未来数据上不再最优。</p><p>直觉告诉我们：找到最优参数就行了。真的吗？</p><h3 id="动手实验-4-参数敏感性扫描" tabindex="-1">动手实验 4：参数敏感性扫描 <a class="header-anchor" href="#动手实验-4-参数敏感性扫描" aria-label="Permalink to &quot;动手实验 4：参数敏感性扫描&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>与 q1/spec-06 同样的扫描技术、不同的教学目的</strong>——必须显式区分；以及**“高原 vs 山峰”的视觉对比要靠 y 轴统一来呈现**。</p><h4 id="起草上下文-任务-3" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-3" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><p>学员第二次见到参数扫描——上次是第一章用来“找最优参数”，这次是用来“判稳健”。这种“老技术新目的”必须在上下文段就讲清楚，否则学员会困惑为什么又来一次：</p><blockquote><p><strong>上下文</strong>：notebook 里已有四策略的整体指标、逐年收益、月度分布、回撤分析。所有分析都基于特定参数（period=20, freq=10, threshold=0.05）。</p><p>当前问题：如果参数稍微变一下，结论还成立吗？</p><p><strong>注意</strong>：这里的参数扫描和第一章 spec-06 不同——</p><ul><li>第一章是“用扫描找最优参数”（目的：挑值）</li><li>本章是“用扫描判稳健性”（目的：判形状）</li></ul><p>同样的技术，完全不同的目的。本章不是要找出比 20 更好的窗口，而是要判断“在 20 附近的所有值，结果是不是都差不多”。</p><p><strong>任务</strong>：扫描 RiskParity 波动率窗口、TopNRanking 动量窗口、止损阈值三个维度，对比“高原型”和“山峰型”。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>同方法不同目的，必须在 spec 里显式区分</strong>。参数扫描在第一章是过拟合的诱因（找漂亮数字），在第五章是过拟合的解药（看是不是高原）。如果 spec 不点名“这次不是为了找最优”，学员会以为“哦又是一次找最优”，下一章 q6 讲过拟合时就接不上。<strong>工具的语义会随章节变化——spec 必须写出当前章节用它干什么</strong>。</p></blockquote><h4 id="起草要求-扫描点设计-极差对比" tabindex="-1">起草要求：扫描点设计 + 极差对比 <a class="header-anchor" href="#起草要求-扫描点设计-极差对比" aria-label="Permalink to &quot;起草要求：扫描点设计 + 极差对比&quot;">​</a></h4><blockquote><p><strong>要求</strong>：</p><ol><li>RiskParity 波动率窗口扫描 <code>vol_period = [10, 15, 20, 25, 30, 40]</code>：中心 20 是 spec-01 选定值，左右对称展开 ±10/±15，加 40 看远端外推；不试 5（5 天太短无法稳定估计波动率）</li><li>TopNRanking 动量窗口扫描 <code>mom_period = [10, 15, 20, 25, 30, 40]</code>（波动率窗口固定 20）</li><li>止损阈值扫描 <code>thresholds = [0.02, 0.03, 0.05, 0.07, 0.10, 0.15, 0.20]</code> + 无止损（共 8 行表，无止损作为最后一行，“止损阈值”列填“无”）</li><li>计算每组的夏普比极差（max - min），打印对比 + 标注“高原型”（极差小）vs“山峰型”（极差大）</li><li>画三子图折线（figsize 15×5，1×3 布局），<strong>y 轴范围统一</strong>——这样 RP 的“平”和 TNR 的“尖”才能立刻可见</li><li>输出“山顶营地”隐喻：高原型像一片平坦的高原（站在哪都差不多高），山峰型像一座尖峰（偏一步就掉下去）</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>参数列表的设计必须有可解释的对称性</strong>。<code>[10, 15, 20, 25, 30, 40]</code> 不是随便挑——中心 20 是当前选定值，左右展开看附近，加远端 40 看外推。spec 不解释扫描点的来历，学员仿写时只会傻乎乎地照抄数字，遇到自己的策略不知道该挑哪些值扫。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：<strong>y 轴统一是“高原 vs 山峰”对比的视觉钥匙</strong>。三个子图各自缩放，看起来都“波动很大”（每个图都填满了画布）；统一 ylim 后，RP 是平的、TNR 是尖的，视觉冲击力立现。<strong>对比图必须共享坐标轴</strong>——这是参数敏感性可视化的固定动作。</p></blockquote><h4 id="起草结果呈现-2" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-2" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：RiskParity 波动率窗口表（6×5）+ TopNRanking 动量窗口表（6×5）+ 止损阈值表（8×5）+ 夏普比极差对比 + 折线敏感性图（1×3）+ 分析文字（<strong>根据实际数据动态描述方向</strong>），用“山顶营地”隐喻收束</p></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q5-how-to-validate/specs/spec-04-parameter-sensitivity.md" target="_blank" rel="noreferrer"><code>specs/spec-04-parameter-sensitivity.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了三组参数敏感性表和一张折线对比图。</p><p>这个实验做了什么？分三组做参数扰动测试。第一组：保持其他参数不变，把 RiskParity 的波动率窗口从 10 天到 40 天逐个试一遍，看夏普比变化多大。第二组：对 TopNRanking 做同样的事，把动量窗口从 10 天到 40 天逐个试。第三组：固定 RiskParity 策略，把止损阈值从 2% 到 20% 逐个试（外加无止损对照）。然后算出每组的夏普比极差（最高减最低），判断策略是“高原型”（参数怎么调都差不多）还是“山峰型”（偏一点就掉到水里）。</p><p><strong>运行结果</strong></p><p>RiskParity 波动率窗口扫描结果如表 5-15 所示。</p><p><strong>表 5-15 RiskParity 波动率窗口敏感性</strong></p><table tabindex="0"><thead><tr><th>窗口(天)</th><th>累计收益</th><th>夏普比</th><th>卡玛比</th><th>回撤</th></tr></thead><tbody><tr><td>10</td><td>104.32%</td><td>1.33</td><td>1.13</td><td>-12.80%</td></tr><tr><td>15</td><td>102.65%</td><td>1.33</td><td>1.13</td><td>-12.64%</td></tr><tr><td>20</td><td>98.01%</td><td>1.29</td><td>1.08</td><td>-12.81%</td></tr><tr><td>25</td><td>96.76%</td><td>1.28</td><td>1.06</td><td>-12.93%</td></tr><tr><td>30</td><td>109.29%</td><td>1.39</td><td>1.10</td><td>-13.49%</td></tr><tr><td>40</td><td>111.45%</td><td>1.40</td><td>1.05</td><td>-14.37%</td></tr></tbody></table><p>夏普比极差: 0.13</p><p>TopNRanking 动量窗口扫描结果如表 5-16 所示。</p><p><strong>表 5-16 TopNRanking 动量窗口敏感性</strong></p><table tabindex="0"><thead><tr><th>窗口(天)</th><th>累计收益</th><th>夏普比</th><th>卡玛比</th><th>回撤</th></tr></thead><tbody><tr><td>10</td><td>104.21%</td><td>1.00</td><td>0.72</td><td>-19.91%</td></tr><tr><td>15</td><td>83.31%</td><td>0.85</td><td>0.73</td><td>-16.78%</td></tr><tr><td>20</td><td>153.03%</td><td>1.27</td><td>1.05</td><td>-17.77%</td></tr><tr><td>25</td><td>144.73%</td><td>1.21</td><td>1.10</td><td>-16.46%</td></tr><tr><td>30</td><td>105.42%</td><td>1.02</td><td>0.87</td><td>-16.64%</td></tr><tr><td>40</td><td>101.54%</td><td>1.00</td><td>0.74</td><td>-19.03%</td></tr></tbody></table><p>夏普比极差: 0.42</p><p>止损阈值的扫描结果如表 5-17 所示（基于 RiskParity 策略，调仓频率 10 天）。</p><p><strong>表 5-17 止损阈值敏感性</strong></p><table tabindex="0"><thead><tr><th>止损阈值</th><th>累计收益</th><th>夏普比</th><th>最大回撤</th><th>交易次数</th></tr></thead><tbody><tr><td>2%</td><td>125.87%</td><td>1.63</td><td>-9.65%</td><td>402</td></tr><tr><td>3%</td><td>118.80%</td><td>1.56</td><td>-11.62%</td><td>394</td></tr><tr><td>5%</td><td>106.23%</td><td>1.43</td><td>-13.07%</td><td>387</td></tr><tr><td>7%</td><td>100.90%</td><td>1.36</td><td>-13.26%</td><td>382</td></tr><tr><td>10%</td><td>106.16%</td><td>1.40</td><td>-12.02%</td><td>375</td></tr><tr><td>15%</td><td>99.30%</td><td>1.32</td><td>-12.51%</td><td>371</td></tr><tr><td>20%</td><td>97.04%</td><td>1.29</td><td>-13.23%</td><td>370</td></tr><tr><td>无止损</td><td>98.01%</td><td>1.29</td><td>-12.81%</td><td>369</td></tr></tbody></table><p>夏普比极差: 0.35</p><p>三组参数的夏普比极差汇总如表 5-18 所示。</p><p><strong>表 5-18 参数敏感性极差对比</strong></p><table tabindex="0"><thead><tr><th>参数组</th><th>夏普比极差</th><th>类型</th></tr></thead><tbody><tr><td>RiskParity</td><td>0.13</td><td>高原型（参数不敏感）</td></tr><tr><td>TopNRanking</td><td>0.42</td><td>山峰型（参数敏感）</td></tr><tr><td>止损阈值</td><td>0.35</td><td>山峰型（参数敏感）</td></tr></tbody></table><p>三组参数的夏普比折线对比如图 5-5 所示。</p><p><img src="'+i+'" alt="参数敏感性对比"></p><h3 id="结果解读-3" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-3" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>最后一个认知升级：<strong>好策略不怕参数变。</strong></p><p><strong>参数敏感性（Parameter Sensitivity）</strong> —— 改一个参数值，策略表现变化有多大。这是策略体检中不可或缺的一项。</p><p>看 RiskParity：波动率窗口从 10 天调到 40 天，夏普比在 1.28-1.40 之间，极差只有 0.13。不管你选哪个窗口，结果都差不多。这叫 <strong>高原型（Plateau）</strong> —— 像一片平坦的高原，站在哪里都差不多高。</p><p>再看 TopNRanking：动量窗口从 10 天调到 40 天，夏普比在 0.85-1.27 之间，极差 0.42——是 RiskParity 的 3 倍多。窗口选 20 天时夏普 1.27，选 15 天时只有 0.85，掉了 1/3。这叫 <strong>山峰型（Peak）</strong> —— 像一座尖峰，只有山尖上最高，稍微偏一步就掉下去。</p><p>想象你在山上找营地。高原型策略像一片平坦的高原——站在哪里都差不多高。山峰型策略像一座尖峰——只有山尖上最高，稍微偏一步就掉下去。你选哪个？</p><p><strong>好策略不依赖某个”魔法参数”。</strong> 如果换一个参数值夏普就<strong>从 1.27 跌到 0.85</strong>（掉了 1/3），说明你可能只是运气好选对了那个值。RiskParity 的有效性来自底层逻辑——“波动大的少买”，不管你用 10 天还是 40 天窗口来衡量波动，排序关系不会剧变。TopNRanking 的高收益则部分依赖于”恰好选对了参数 20”。</p><p>这也呼应了 Step 2 的发现：TopNRanking 在某些年份负收益、对参数敏感，它的高收益可能有运气成分。RiskParity 虽然收益不如 TopNRanking 高，但参数稳健、年度一致性好——这才是更可靠的策略。</p><p><strong>选策略就像选营地——要选高原，不选尖峰。</strong></p><p>回头看：还记得第一章末尾你亲眼看到的那次“参数扫描里冠军在样本外掉到了水下”吗？那就是山峰型在参数 + 时间两个维度上同时露出的脸——你当时亲手撞了一次墙，从此对回测多一份警觉。</p><p><strong>这一章的高原型 vs 山峰型，正是“做要规则、看要指标、还要怀疑你的指标”这句口号里“看 → 疑”的桥梁——下一章你会把“疑”练成主线。</strong></p><hr><h2 id="_5-5-回头看-你刚才做了什么" tabindex="-1">5.5 回头看：你刚才做了什么？ <a class="header-anchor" href="#_5-5-回头看-你刚才做了什么" aria-label="Permalink to &quot;5.5 回头看：你刚才做了什么？&quot;">​</a></h2><p><strong>这一节是“看”的操作流程总图——把四步实验铺成你以后每次接到一份回测都能照着走的检查路径。</strong> 四步实验，一张完整的“策略体检地图”：</p><ul><li><strong>Step 1: 跟什么比？</strong> -- 基准 + Alpha（超额收益）+ 多维指标（夏普比/卡玛比/索提诺比）</li><li><strong>Step 2: 每年都有收益吗？</strong> -- 分段检验 + 策略类型弱点（动量滞后性）</li><li><strong>Step 3: 收益结构什么样？</strong> -- 胜率陷阱/盈亏比/盈亏因子 + 回撤深度/恢复时间</li><li><strong>Step 4: 参数动一动？</strong> -- 参数敏感性 + 高原型 vs 山峰型</li></ul><p>从今以后，拿到任何策略的回测结果，你都可以用这四步做一次“全面体检”，五个维度的体检问题如表 5-19 所示。</p><p><strong>表 5-19 策略体检维度速查</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>问题</th></tr></thead><tbody><tr><td>基准</td><td>跑赢了吗？</td></tr><tr><td>年度</td><td>每年都赚吗？</td></tr><tr><td>分布</td><td>赚法健康吗？</td></tr><tr><td>回撤</td><td>最坏到什么程度？</td></tr><tr><td>参数</td><td>参数改了还行吗？</td></tr></tbody></table><p><strong>从“看收益率”到“全面体检”——这是本章最重要的认知升级。</strong></p><h3 id="四个最容易让你-被自己骗-的陷阱" tabindex="-1">四个最容易让你“被自己骗”的陷阱 <a class="header-anchor" href="#四个最容易让你-被自己骗-的陷阱" aria-label="Permalink to &quot;四个最容易让你“被自己骗”的陷阱&quot;">​</a></h3><p>每个维度对应一种最容易踩的陷阱——它们各有不同名字，但本质都是“指标好看，结果不靠谱”。下次别人（或者你自己）拿一份“漂亮”的回测来，先用这四个 lens 扫一遍：</p><ol><li><strong>基准陷阱</strong>——只看年化收益，没和“什么都不做”对比。EqualWeight 累计 84% 看着还行，等权买入持有同期 95%——你忙了半天反而落后。</li><li><strong>整体陷阱</strong>——只看多年累计，掩盖了某些年份的大亏。TopNRanking 累计第一，但 2021 年是唯一亏钱的策略（-10.09%），其他三个策略同期都是正收益——普通人在那年就放弃了。</li><li><strong>胜率陷阱</strong>——胜率 90% 不等于赚钱。一次大亏可以抹平十次小赚，真正决定结果的是盈亏比和盈亏因子。</li><li><strong>山峰陷阱</strong>——某个参数最优，稍微一偏夏普就掉一大截。这往往不是规律，是巧合——和第一章末尾你撞上的那堵墙是同一种东西。</li></ol><p><strong>四个陷阱合起来，就是“看要指标”这一层在跟你强调的事——指标越多越好；但每个指标只看一面，你得把四面合起来看，才能少被自己骗。</strong></p><hr><h2 id="_5-6-本章总结" tabindex="-1">5.6 本章总结 <a class="header-anchor" href="#_5-6-本章总结" aria-label="Permalink to &quot;5.6 本章总结&quot;">​</a></h2><h3 id="策略进化路径" tabindex="-1">策略进化路径 <a class="header-anchor" href="#策略进化路径" aria-label="Permalink to &quot;策略进化路径&quot;">​</a></h3><p><strong>第四章产出：RiskParity + 止损 + 三个对比策略</strong></p><ul><li>Step 1: 跟基准比 -- 不是所有策略都跑赢了“什么都不做”</li><li>Step 2: 逐年拆 -- 某些年份亏损，动量策略有结构性弱点</li><li>Step 3: 看分布 -- 胜率是陷阱，盈亏比才是关键</li><li>Step 4: 动参数 -- 高原型稳，山峰型脆</li></ul><p><strong>第五章产出：完整的策略评估方法论 + “体检清单”</strong></p><h3 id="概念速查表" tabindex="-1">概念速查表 <a class="header-anchor" href="#概念速查表" aria-label="Permalink to &quot;概念速查表&quot;">​</a></h3><p>本章涉及的核心概念汇总如表 5-20 所示，方便随时回查。</p><p><strong>表 5-20 第五章核心概念速查</strong></p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th><th>类比</th></tr></thead><tbody><tr><td>基准（Benchmark）</td><td>用来做比较的参照物——“什么都不做”时你能赚多少</td><td>考试的“及格线”</td></tr><tr><td>超额收益 / Alpha</td><td>策略收益减去基准收益——超出及格线的部分才是你的本事</td><td>第一章电梯/楼梯类比，本章放回“基准之后才能算”的语境</td></tr><tr><td>卡玛比（Calmar）</td><td>年化收益 / 最大回撤</td><td>每承受 1% 最大回撤换多少收益</td></tr><tr><td>索提诺比（Sortino）</td><td>只用下行波动率做分母</td><td>上涨波动不算风险</td></tr><tr><td>分段检验</td><td>把回测按年份拆开</td><td>整体及格不等于每科都及格</td></tr><tr><td>动量滞后性</td><td>动量指标基于“过去涨了多少”</td><td>后视镜——过去涨不代表未来继续涨</td></tr><tr><td>胜率的陷阱</td><td>胜率本身意义不大</td><td>胜率 90% 也可能亏钱</td></tr><tr><td>盈亏比（Win/Loss Ratio）</td><td>平均盈利 / 平均亏损</td><td>真正决定收益的指标</td></tr><tr><td>盈亏因子（Profit Factor）</td><td>总盈利 / 总亏损</td><td>大于 1 赚钱，大于 2 优秀</td></tr><tr><td>水下曲线（Underwater）</td><td>每天距离历史最高点跌了多少</td><td>“你在水下待了多久”</td></tr><tr><td>回撤恢复时间</td><td>从最低点爬回前高要多久</td><td>比深度更影响持有体验</td></tr><tr><td>参数敏感性</td><td>改参数后结果变化多大</td><td>好策略不怕参数变</td></tr><tr><td>高原型 vs 山峰型</td><td>高原：参数怎么调都差不多。山峰：偏一点夏普极差大</td><td>找营地选高原不选尖峰</td></tr></tbody></table><h3 id="本章核心认知" tabindex="-1">本章核心认知 <a class="header-anchor" href="#本章核心认知" aria-label="Permalink to &quot;本章核心认知&quot;">​</a></h3><p>走完四步实验，沉淀下来的认知如表 5-21 所示。</p><p><strong>表 5-21 第五章核心认知</strong></p><table tabindex="0"><thead><tr><th>认知</th><th>来源</th></tr></thead><tbody><tr><td>“好不好”必须有参照物——基准</td><td>Step 1 实验</td></tr><tr><td>跑赢基准的部分才是 Alpha——你的技能回报</td><td>Step 1 实验</td></tr><tr><td>夏普比、卡玛比、索提诺比是三把不同的尺子</td><td>Step 1 实验</td></tr><tr><td>整体指标可能掩盖年度亏损——分段检验</td><td>Step 2 实验</td></tr><tr><td>动量策略在反复震荡的市场中有结构性弱点——滞后性</td><td>Step 2 深挖</td></tr><tr><td>胜率是陷阱——真正决定收益的是盈亏比，优秀策略的秘诀是“小亏大赚”</td><td>Step 3 实验</td></tr><tr><td>回撤不只是深度，还有恢复时间——水下曲线</td><td>Step 3 实验</td></tr><tr><td>好策略不怕参数变——高原型 &gt;&gt; 山峰型</td><td>Step 4 实验</td></tr><tr><td>先猜后验，数据说了算</td><td>贯穿全章</td></tr></tbody></table><h3 id="带走的问题" tabindex="-1">带走的问题 <a class="header-anchor" href="#带走的问题" aria-label="Permalink to &quot;带走的问题&quot;">​</a></h3><ul><li>体检工具给了你客观数据。但<strong>回测本身可信吗？</strong> 回测能调参数让收益翻倍——这是真的好，还是自欺欺人？ → 第六章</li><li>如果你在 2023 年跑回测发现某个策略 2021-2023 表现好，你怎么知道它 2024 年还会好？ → 第六章</li></ul><p>带着这两个问题进入下一章——它们正是本书口号“<strong>做要规则、看要指标、还要怀疑你的指标</strong>”中“<strong>疑</strong>”那一步要训练的核心。这一章你已经把“看”练了一遍，下一章我们专门把“疑”练成主线。</p><blockquote><p>本章所有代码的可运行版本见 <code>notebooks/q5-how-to-validate.ipynb</code></p></blockquote><hr><h2 id="拓展阅读" tabindex="-1">拓展阅读 <a class="header-anchor" href="#拓展阅读" aria-label="Permalink to &quot;拓展阅读&quot;">​</a></h2><p>本章正文聚焦“四步策略体检”。下面三段是动手之前可以省略的视野铺垫——读完正文回头看，你会更清楚指标背后的量化惯例。</p><h3 id="为什么-年化-用-252-这个数字" tabindex="-1">为什么“年化”用 252 这个数字 <a class="header-anchor" href="#为什么-年化-用-252-这个数字" aria-label="Permalink to &quot;为什么“年化”用 252 这个数字&quot;">​</a></h3><p>正文反复说“年化收益率”、“年化波动率”——背后都隐含一个换算系数：<strong>252</strong>。</p><p>A 股一年大约 250-252 个交易日（节假日不开盘），美股 252 个，全球主流市场都接近这个数。所以“日 → 年”的换算是：<strong>年化收益率 ≈ 平均日收益率 × 252</strong>；<strong>年化波动率 ≈ 日收益率标准差 × √252</strong>（注意是开根号，不是直接乘）。比如一个策略日波动率 1%，年化波动率 ≈ 1% × √252 ≈ 15.87%。回测里所有“年化”指标都用了这个换算——不是定理，但是行业惯例。</p><h3 id="夏普比率-vs-信息比率-ir" tabindex="-1">夏普比率 vs 信息比率（IR） <a class="header-anchor" href="#夏普比率-vs-信息比率-ir" aria-label="Permalink to &quot;夏普比率 vs 信息比率（IR）&quot;">​</a></h3><p>夏普比率 = 年化收益 / 年化波动。但你可能在论文或基金报告里见过另一个相似的指标——<strong>信息比率（Information Ratio, IR）</strong>。</p><p>二者长得很像，区别在分子：<strong>夏普比率分子是策略的“全部收益”，IR 分子是“策略相对基准的超额收益（Alpha）”</strong>。也就是说，IR 衡量的是“主动管理的性价比”——剔除了 Beta，纯看 Alpha 部分。基金经理之间互相比 IR 比夏普比率更公平，因为大家都被市场抬着走，IR 才能看出谁真的有本事。本书课程默认用夏普比率（更直观），但你以后看到 IR 不要感到陌生——它只是把“分子换成 Alpha”的夏普比率。</p><h3 id="索提诺比的-mar-参数" tabindex="-1">索提诺比的“MAR”参数 <a class="header-anchor" href="#索提诺比的-mar-参数" aria-label="Permalink to &quot;索提诺比的“MAR”参数&quot;">​</a></h3><p>正文说索提诺比 = 年化收益 / 下行波动率。但什么算“下行”？业界常用的定义是：<strong>收益低于某个阈值（叫 MAR，Minimum Acceptable Return，最低可接受收益率）的那部分波动</strong>。</p><p>最常见的两种 MAR 选法：①<strong>MAR = 0</strong>——把“亏损”定义为“日收益率 &lt; 0”，最简单；②<strong>MAR = 无风险利率</strong>（如美债 5%）——把“没跑赢国债”也算“下行”，更严格。本书计算时用的是 MAR = 0（更直观），但你看到不同来源的索提诺比数值有差异时，先确认它们用的是哪种 MAR——否则比的不是同一个东西。</p><hr><h2 id="反馈与读者群" tabindex="-1">反馈与读者群 <a class="header-anchor" href="#反馈与读者群" aria-label="Permalink to &quot;反馈与读者群&quot;">​</a></h2><p>如果你发现本章有错别字、概念不清或实验结果不一致，欢迎 <a href="https://github.com/xingwudao/xquant-beginner/issues/new/choose" target="_blank" rel="noreferrer">提交 GitHub Issue</a>。</p><p>课程、正式书和后续更新见 <a href="https://xquant.shop/courses" target="_blank" rel="noreferrer">xquant.shop/courses</a>。</p><p>添加作者微信 <code>xquanter</code> 进入读者群。请备注：<code>XQuant 读者</code>。</p>',266)]))}const m=d(h,[["render",l]]);export{R as __pageData,m as default};
